// Daten aus vorherigen Nodes zusammenführen
const evccState = $('evcc: GET /api/state').item.json;
const influxData = $('InfluxDB: Verbrauchshistorie').item.json;

// evcc state auslesen
const soc = Math.round(evccState?.battery?.soc ?? 50);

// Solar-Prognose morgen: forecast.solar.tomorrow.energy in Wh → kWh
const solarForecastKwh = Math.round((evccState?.forecast?.solar?.tomorrow?.energy ?? 0) / 1000 * 10) / 10;

// Tibber-Preise für morgen: forecast.grid enthält heute+morgen als 15-min-Slots
// Wert ist in EUR → mal 100 = ct/kWh
const allSlots = evccState?.forecast?.grid ?? [];
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowStr = tomorrow.toISOString().split('T')[0];
const tomorrowPrices = allSlots
  .filter(slot => slot.start?.startsWith(tomorrowStr))
  .map(slot => ({ time: slot.start, price_ct: Math.round(slot.value * 100 * 100) / 100 }));

// InfluxDB Verbrauch (Fallback: 10 kWh wenn nicht verfügbar)
let avgConsumptionKwh = 10.0;
let influxFallback = true;
try {
  const results = influxData?.results?.[0]?.series?.[0]?.values ?? [];
  if (results.length > 0) {
    const validValues = results.map(r => r[1]).filter(v => v != null && !isNaN(v));
    if (validValues.length > 0) {
      const total = validValues.reduce((sum, v) => sum + v, 0);
      avgConsumptionKwh = Math.round(total / 1000 * 100) / 100; // Wh → kWh
      influxFallback = false;
    }
  }
} catch (e) {
  // Fallback bleibt 10 kWh
}

// Einspeise-Logik Status
const haDischarge = $('HA: Einspeise-Schalter').item.json?.state === 'on';

// Abbruch wenn keine Tibber-Preise für morgen verfügbar
if (tomorrowPrices.length === 0) {
  throw new Error('Keine Tibber-Preise fuer morgen verfuegbar – Optimizer abgebrochen');
}

return [{
  json: {
    soc,
    solar_kwh: solarForecastKwh,
    consumption_kwh: avgConsumptionKwh,
    tibber_prices: tomorrowPrices,
    discharge_active: haDischarge,
    influx_fallback: influxFallback
  }
}];

