const response = $input.item.json;

// Claude-Response parsen
let threshold = null;
let reasoning = '';

try {
  // Versuche direktes JSON-Parsing
  const text = response?.content ?? response?.text ?? JSON.stringify(response);
  const match = text.match(/\{[^}]+\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    threshold = parseFloat(parsed.threshold_ct);
    reasoning = parsed.reasoning ?? '';
  }
} catch (e) {
  // Fallback: threshold bleibt null → Fehler-Node greift
}

if (threshold === null || isNaN(threshold)) {
  throw new Error('Claude-Response konnte nicht geparst werden: ' + JSON.stringify(response));
}

// Sicherheitscheck: Threshold zwischen 0 und 50 ct
threshold = Math.min(50, Math.max(0, threshold));

return [{
  json: {
    threshold_ct: threshold,
    reasoning,
    timestamp: new Date().toISOString()
  }
}];
